diff --git a/llvm/lib/Transforms/InstCombine/InstCombineLoadStoreAlloca.cpp b/llvm/lib/Transforms/InstCombine/InstCombineLoadStoreAlloca.cpp
index 365a9b3aafc9..a09afd4c76e0 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineLoadStoreAlloca.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineLoadStoreAlloca.cpp
@@ -1403,6 +1403,7 @@ static bool equivalentAddressValues(Value *A, Value *B) {
 }

 Instruction *InstCombinerImpl::visitStoreInst(StoreInst &SI) {
+	LLVM_DEBUG(dbgs() << "Processing StoreInst: " << SI << "\n");
   Value *Val = SI.getOperand(0);
   Value *Ptr = SI.getOperand(1);

@@ -1425,6 +1426,7 @@ Instruction *InstCombinerImpl::visitStoreInst(StoreInst &SI) {
   // If the RHS is an alloca with a single use, zapify the store, making the
   // alloca dead.
   if (Ptr->hasOneUse()) {
+	if (!SI.use_empty()) return nullptr; // Skip if the instruction has uses.
     if (isa<AllocaInst>(Ptr))
       return eraseInstFromFunction(SI);
     if (GetElementPtrInst *GEP = dyn_cast<GetElementPtrInst>(Ptr)) {
diff --git a/llvm/lib/Transforms/Utils/Local.cpp b/llvm/lib/Transforms/Utils/Local.cpp
index babd7f6b3a05..1285368a93c5 100644
--- a/llvm/lib/Transforms/Utils/Local.cpp
+++ b/llvm/lib/Transforms/Utils/Local.cpp
@@ -482,7 +482,10 @@ bool llvm::wouldInstructionBeTriviallyDead(const Instruction *I,

     if (II->isLifetimeStartOrEnd()) {
       auto *Arg = II->getArgOperand(1);
+	if (!Arg) return false; // Ensure Arg is not null before accessing its uses.
+	if (!Arg) return false; // Ensure Arg is not null before accessing its uses.
       // If the only uses of the alloca are lifetime intrinsics, then the
+	if (!Arg->hasNUsesOrMore(1)) return false; // Ensure Arg has a valid use list.
       // intrinsics are dead.
       return llvm::all_of(Arg->uses(), [](Use &Use) {
         return isa<LifetimeIntrinsic>(Use.getUser());

